mapper.select:
select job_name, watermark_at, generated_at, status, message
from analytics_rollup_watermarks
where job_name = #{jobName}

mapper.insert:
insert into analytics_rollup_watermarks(
    job_name, watermark_at, generated_at, status, message, trace_id, updated_at
)
values (
    #{jobName}, #{watermarkAt}, #{generatedAt}, #{status}, #{message}, #{traceId}, #{updatedAt}
)

mapper.update:
update analytics_job_locks
set owner_id = #{ownerId},
    locked_until = #{lockedUntil},
    updated_at = #{now}
where lock_name = #{lockName}
  and (locked_until <= #{now} or owner_id = #{ownerId})

mapper.delete:
delete from analytics_job_locks
where lock_name = #{lockName}
  and owner_id = #{ownerId}

